from flask import Flask, session, redirect, url_for, request, escape

app = Flask(__name__)
app.secret_key = b'_5#y2L"F4Q8z\n\xec]/' # Bu, üretim ortamında çok daha uzun ve karmaşık olmalıdır.

@app.route('/')
def index():
    if 'username' in session:
        return f'Merhaba {escape(session["username"])}! <a href="/logout">Çıkış yap</a>'
    return 'Giriş yapmadınız. <a href="/login/testuser">Test kullanıcısı olarak giriş yap</a>'

@app.route('/login/<username>')
def login(username):
    session['username'] = username
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.pop('username', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)
